import{_ as e,o as l,c as t,ag as i}from"./chunks/framework.BZohXCq9.js";const q=JSON.parse('{"title":"改进备忘","description":"","frontmatter":{"title":"改进备忘"},"headers":[],"relativePath":"novels/jin-gu-yao/behind-the-scenes/improvements.md","filePath":"novels/jin-gu-yao/behind-the-scenes/improvements.md","lastUpdated":1773922498000}'),o={name:"novels/jin-gu-yao/behind-the-scenes/improvements.md"};function r(n,a,u,h,s,d){return l(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="改进备忘" tabindex="-1">改进备忘 <a class="header-anchor" href="#改进备忘" aria-label="Permalink to &quot;改进备忘&quot;">​</a></h1><p>前五章完成后的复盘笔记。记录已完成的修改、待解决的问题和后续写作方向。</p><h2 id="已完成的修改" tabindex="-1">已完成的修改 <a class="header-anchor" href="#已完成的修改" aria-label="Permalink to &quot;已完成的修改&quot;">​</a></h2><h3 id="文字层面" tabindex="-1">文字层面 <a class="header-anchor" href="#文字层面" aria-label="Permalink to &quot;文字层面&quot;">​</a></h3><ul><li>清理了全书重复意象：<code>背影笔直/像树</code>、<code>语气像说天气</code>、<code>后来想了很久</code> 等高频表达，每种只保留最有力的一次</li><li>修复了第五章两处结构性重复（&quot;帐篷外面——不，是屋子外面&quot;段落重复；&quot;停了很久。久到三娘以为他不打算说了&quot;连续出现两次）</li><li>精简了第五章谈判场景中对第四章内容的大量复述——三娘不再重新叙述何潘仁的完整往事，改为直接说出妻子名字&quot;康月&quot;，一刀到位</li><li>减少了&quot;三宝/在&quot;呼应模式的过度使用</li><li>补充了第二章小吏视角跳切的时空锚点（&quot;同一时刻。鄠县南门。&quot;）</li></ul><h3 id="人物层面" tabindex="-1">人物层面 <a class="header-anchor" href="#人物层面" aria-label="Permalink to &quot;人物层面&quot;">​</a></h3><ul><li>在第三章为三娘增加了一个失算时刻——她没料到柴哲威一句闲话让粮食消耗计划提前失控。&quot;她低估了自己儿子的嗓门。&quot;</li><li>修正了何潘仁妻子的姓氏：<code>阿史那·月</code> → <code>康月</code>（阿史那是突厥皇族姓氏，与粟特商人身份不符；康是昭武九姓之一，与何潘仁的康国出身一致）</li><li>在第四章补充了何潘仁说出妻子名字的情节，为第五章三娘知道这个名字提供信息来源</li></ul><hr><h2 id="待改进-两个孩子的行为模式固化" tabindex="-1">待改进：两个孩子的行为模式固化 <a class="header-anchor" href="#待改进-两个孩子的行为模式固化" aria-label="Permalink to &quot;待改进：两个孩子的行为模式固化&quot;">​</a></h2><p>柴哲威和柴令武在前五章承担了大量&quot;调剂幽默&quot;功能，但行为模式已经固化：</p><ul><li>哲威 = 扮大人 + 模仿父亲</li><li>令武 = 哭 + 骑马三宝 + 鼻涕</li></ul><p>同类型场景在五章内出现了 8-10 次，读者的新鲜感会衰减。</p><h3 id="可能的方向" tabindex="-1">可能的方向 <a class="header-anchor" href="#可能的方向" aria-label="Permalink to &quot;可能的方向&quot;">​</a></h3><ul><li><strong>哲威开始察觉&quot;不对劲&quot;</strong>：他五岁了，不傻。可以让他注意到一些大人以为孩子看不懂的事——比如庄园外突然多了很多人，或者娘亲晚上不睡觉。不需要他理解，只需要他问出一个让三娘愣住的问题。</li><li><strong>令武跟何潘仁的马建立关系</strong>：第五章已经铺了令武对那匹西域马的兴趣，可以发展成一条小线——三岁小孩和一匹战马的互动，既有趣又能侧面展现何潘仁的态度变化。</li><li><strong>适当减少孩子戏份</strong>：后续章节中，孩子不必每个场景都出现。让他们的出场有选择性，每次出场都带来新的信息或情感。</li></ul><hr><h2 id="后续写作方向" tabindex="-1">后续写作方向 <a class="header-anchor" href="#后续写作方向" aria-label="Permalink to &quot;后续写作方向&quot;">​</a></h2><h3 id="_1-鄠县县令正面出场-建议第六章" tabindex="-1">1. 鄠县县令正面出场（建议第六章） <a class="header-anchor" href="#_1-鄠县县令正面出场-建议第六章" aria-label="Permalink to &quot;1. 鄠县县令正面出场（建议第六章）&quot;">​</a></h3><p>这是目前最好的悬念。从第一章末尾就开始落子：</p><ul><li>第一章：县衙灯下看公文</li><li>第二章：南门小吏记录</li><li>第三章：数人头的老汉</li><li>第五章：&quot;砍柴人&quot;出现</li></ul><p>五章铺垫足够了，第六章应该让他正面登场。</p><p><strong>关键原则</strong>：他不能是一个蠢笨的反派。他应该和三娘旗鼓相当——同样精明，同样在乱世中下注。他留在鄠县不跑，说明他有自己的算盘。让读者觉得&quot;这个人如果站在三娘这边该多好&quot;，这样对抗才有张力。</p><h3 id="_2-粮食危机需要真正爆发" tabindex="-1">2. 粮食危机需要真正爆发 <a class="header-anchor" href="#_2-粮食危机需要真正爆发" aria-label="Permalink to &quot;2. 粮食危机需要真正爆发&quot;">​</a></h3><p>孙守道算出的&quot;十八天&quot;不能被轻松化解。如果每次困难都被三娘提前想到并解决，读者会丧失紧张感。</p><p><strong>可能的方向</strong>：</p><ul><li>&quot;借粮&quot;不完全成功——某个大户拒绝了，甚至向县令告密</li><li>何潘仁的人和三娘原有的三百人之间发生冲突（抢粮、打架）</li><li>让三娘面对一个她没有答案的问题，被迫临场应变</li></ul><h3 id="_3-穿插柴绍线" tabindex="-1">3. 穿插柴绍线 <a class="header-anchor" href="#_3-穿插柴绍线" aria-label="Permalink to &quot;3. 穿插柴绍线&quot;">​</a></h3><p>柴绍离开后完全消失了。偶尔穿插一小段他在去太原路上（或到了太原后）的情况，可以：</p><ul><li>保持读者对这条线的记忆</li><li>与三娘的处境形成对照——丈夫在那边做什么，妻子在这边做什么</li><li>为后续两人重逢（以及发现妻子比自己厉害）埋下伏笔</li></ul><p>不需要多，每隔一两章用一个分隔符切过去写三五行就够了。</p><h3 id="_4-给三娘制造一次真正的危机" tabindex="-1">4. 给三娘制造一次真正的危机 <a class="header-anchor" href="#_4-给三娘制造一次真正的危机" aria-label="Permalink to &quot;4. 给三娘制造一次真正的危机&quot;">​</a></h3><p>前五章三娘没有犯过一次真正意义上的错误。第三章加的&quot;低估儿子嗓门&quot;是小失算，后续需要一次更大的——比如：</p><ul><li>她以为县令只是在观望，结果县令已经向长安留守报信</li><li>她以为某个投奔者可靠，结果是眼线</li><li>何潘仁的某个副手不服她，挑起内部分裂</li></ul><p>让她应对失误的方式来展现能力，比她永远正确更有说服力。</p>',33)])])}const p=e(o,[["render",r]]);export{q as __pageData,p as default};
